arguments.file_text:
#:property AllowUnsafeBlocks=true

Span<nint> a = stackalloc nint[4];
a[0] = 10;
a[1] = 20;
a[2] = 30;
a[3] = 40;

nint sum = 0;
foreach (var v in a)
    sum += v;

Console.WriteLine($"Span<nint> stackalloc works! Sum = {sum}, element size = {nint.Size} bytes");

Span<nuint> b = stackalloc nuint[3];
b[0] = 100;
b[1] = 200;
b[2] = 300;

nuint usum = 0;
foreach (var v in b)
    usum += v;

Console.WriteLine($"Span<nuint> stackalloc works! Sum = {usum}");

